// ================= CONFIG =================
const CONFIG = {
  HOJA_DB: 'OFICIOS_DB',
  HOJA_CONTROL: 'CONTROL',
  HOJA_FORM1: 'RESPUESTAS_FORM',
  HOJA_FORM2: 'RESPUESTAS_FORM2',
  HOJA_LOGS: 'LOGS',
  FORM2_URL: 'https://forms.gle/MtRV5MBbJ6GBPGnb7',
  EMAILS: ['vicerrectoria.academica@uptc.edu.co']
};

// ================= LOG =================
function log(tipo, mensaje) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let hoja = ss.getSheetByName(CONFIG.HOJA_LOGS);

  if (!hoja) {
    hoja = ss.insertSheet(CONFIG.HOJA_LOGS);
    hoja.appendRow(["Fecha", "Tipo", "Mensaje"]);
  }

  hoja.appendRow([new Date(), tipo, mensaje]);
}

// ================= FORMULARIO 1 =================
function guardarForm1(e) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const db = ss.getSheetByName(CONFIG.HOJA_DB);
    const control = ss.getSheetByName(CONFIG.HOJA_CONTROL);

    const datos = e.values;

    const fecha = datos[1];
    const funcionario = datos[4];
    const linea = datos[5];

    // 🔢 consecutivo
    let consecutivoNum = control.getRange("B1").getValue();
    if (!consecutivoNum || isNaN(consecutivoNum)) consecutivoNum = 260;

    consecutivoNum++;
    control.getRange("B1").setValue(consecutivoNum);

    const consecutivo = 'VA-' + String(consecutivoNum).padStart(3, '0');

    const filaDB = db.getLastRow() + 1;

    db.getRange(filaDB, 1, 1, 12).setValues([[
      consecutivo,   // ID
      fecha,
      '',            // dirigido
      '',            // asunto
      funcionario,
      '',            // proceso
      linea,
      '',            // sublinea
      '',            // soporte
      '',            // anexos
      '',
      ''
    ]]);

    // 📧 correo (FUNCIONA SI EL FORM CAPTURA EMAIL)
    let correo = "";
    try {
      correo = e.namedValues["Dirección de correo electrónico"]?.[0] || "";
    } catch (err) {}

    let destinatarios = [...CONFIG.EMAILS];
    if (correo && !destinatarios.includes(correo)) {
      destinatarios.push(correo);
    }

    GmailApp.sendEmail(
      destinatarios.join(','),
      `Solicitud registrada ${consecutivo}`,
      `Su solicitud fue creada correctamente.\n\nID: ${consecutivo}\n\nComplete aquí:\n${CONFIG.FORM2_URL}`
    );

    log("OK", "Form1 → creado " + consecutivo);

  } catch (error) {
    log("ERROR", "Form1: " + error.message);
  }
}

// ================= FORMULARIO 2 =================
function guardarForm2(e) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const db = ss.getSheetByName(CONFIG.HOJA_DB);

    const datos = e.values;

    const id = datos[1];
    const dirigido = datos[2];
    const asunto = datos[3];
    const proceso = datos[4];
    const sublinea = datos[5];
    const soporte = datos[6];
    const anexos = datos[7];

    const registros = db.getDataRange().getValues();

    for (let i = 1; i < registros.length; i++) {

      if (registros[i][0] == id) {

        const fila = i + 1;

        db.getRange(fila, 3).setValue(dirigido);
        db.getRange(fila, 4).setValue(asunto);
        db.getRange(fila, 6).setValue(proceso);
        db.getRange(fila, 8).setValue(sublinea);
        db.getRange(fila, 9).setValue(soporte);
        db.getRange(fila, 10).setValue(anexos);

        log("OK", "Form2 → actualizado " + id);
        return;
      }
    }

    // 🔥 SI NO EXISTE → LO CREA
    const nuevaFila = db.getLastRow() + 1;

    db.getRange(nuevaFila, 1, 1, 12).setValues([[
      id,
      '',
      dirigido,
      asunto,
      '',
      proceso,
      '',
      sublinea,
      soporte,
      anexos,
      '',
      ''
    ]]);

    log("WARNING", "Form2 creó registro: " + id);

  } catch (error) {
    log("ERROR", "Form2: " + error.message);
  }
}
